BEGIN TRANSACTION;
CREATE TABLE artifact (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  phase_id TEXT NOT NULL REFERENCES phase(phase_id) ON DELETE CASCADE,
  kind TEXT NOT NULL,
  path TEXT NOT NULL,
  description TEXT,
  UNIQUE (phase_id, kind, path)
);
CREATE TABLE memory (
  key TEXT PRIMARY KEY,
  value TEXT NOT NULL,
  notes TEXT,
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE meta (
  key TEXT PRIMARY KEY,
  value TEXT NOT NULL,
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE metric (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  phase_id TEXT NOT NULL REFERENCES phase(phase_id) ON DELETE CASCADE,
  scope TEXT NOT NULL,
  name TEXT NOT NULL,
  before_value TEXT,
  after_value TEXT,
  delta TEXT,
  unit TEXT,
  notes TEXT,
  UNIQUE (phase_id, scope, name)
);
CREATE TABLE phase (
  phase_id TEXT PRIMARY KEY,
  branch TEXT,
  status TEXT NOT NULL CHECK (status IN ('planned','in_progress','complete','merged','blocked','unknown')),
  pr_number INTEGER,
  pr_url TEXT,
  commit_hash TEXT,
  selected_target TEXT,
  classification TEXT,
  summary TEXT,
  next_recommended_target TEXT,
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE validation (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  phase_id TEXT NOT NULL REFERENCES phase(phase_id) ON DELETE CASCADE,
  command TEXT NOT NULL,
  status TEXT NOT NULL,
  notes TEXT,
  UNIQUE (phase_id, command)
);
CREATE VIEW phase_summary AS
SELECT
  phase_id,
  status,
  branch,
  pr_number,
  commit_hash,
  selected_target,
  classification,
  summary,
  next_recommended_target
FROM phase
ORDER BY phase_id;
DELETE FROM "sqlite_sequence";
COMMIT;
